json::Object
Asg2Json::operator()(StringLiteral* obj)
{
  json::Object ret;
  Obj::Walked guard(obj);

  ret["kind"] = "StringLiteral";

  std::string value;
  value.push_back('"');
  for (auto&& c : obj->val) {
    switch (c) {
      case '\'':
        value += "\\'";
        break;

      case '"':
        value += "\\\"";
        break;

      case '\?':
        value += "\\?";
        break;

      case '\\':
        value += "\\\\";
        break;

      case '\a':
        value += "\\a";
        break;

      case '\b':
        value += "\\b";
        break;

      case '\f':
        value += "\\f";
        break;

      case '\n':
        value += "\\n";
        break;

      case '\r':
        value += "\\r";
        break;

      case '\t':
        value += "\\t";
        break;

      case '\v':
        value += "\\v";
        break;

      default:
        value.push_back(c);
    }
  }
  value.push_back('"');
  ret["value"] = std::move(value);

  return ret;
}

