json::Object
Asg2Json::operator()(ParenExpr* obj)
{
  json::Object ret;
  Obj::Walked guard(obj);

  ret["kind"] = "ParenExpr";

  json::Array inner;
  inner.push_back(self(obj->sub));
  ret["inner"] = std::move(inner);

  return ret;
}

json::Object
Asg2Json::operator()(UnaryExpr* obj)
{
  assert(obj->sub);

  json::Object ret;
  Obj::Walked guard(obj);

  ret["kind"] = "UnaryOperator";

  switch (obj->op) {
    case UnaryExpr::kPos:
      ret["opcode"] = "+";
      break;

    case UnaryExpr::kNeg:
      ret["opcode"] = "-";
      break;

    case UnaryExpr::kNot:
      ret["opcode"] = "!";
      break;

    default:
      ABORT();
  }

  json::Array inner;
  inner.push_back(self(obj->sub));
  ret["inner"] = std::move(inner);

  return ret;
}

